diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..9e8c7d62cbba 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,55 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // Simplify OR/AND of comparisons with constants where one implies the other.
+  // For ordered comparisons with the same variable operand:
+  // OR: (x olt C1) | (x olt C2) where C1 < C2 -> (x olt C2)
+  // OR: (x ole C1) | (x ole C2) where C1 < C2 -> (x ole C2)
+  // OR: (x ogt C1) | (x ogt C2) where C1 < C2 -> (x ogt C1)
+  // OR: (x oge C1) | (x oge C2) where C1 < C2 -> (x oge C1)
+  // AND: (x olt C1) & (x olt C2) where C1 < C2 -> (x olt C1)
+  // AND: (x ole C1) & (x ole C2) where C1 < C2 -> (x ole C1)
+  // AND: (x ogt C1) & (x ogt C2) where C1 < C2 -> (x ogt C2)
+  // AND: (x oge C1) & (x oge C2) where C1 < C2 -> (x oge C2)
+  const APFloat *LHSC, *RHSC;
+  if (LHS0 == RHS0 &&
+      match(LHS1, m_APFloatAllowPoison(LHSC)) &&
+      match(RHS1, m_APFloatAllowPoison(RHSC))) {
+    // Only handle ordered comparisons with the same predicate
+    bool IsLessThan = (PredL == FCmpInst::FCMP_OLT || PredL == FCmpInst::FCMP_OLE);
+    bool IsGreaterThan = (PredL == FCmpInst::FCMP_OGT || PredL == FCmpInst::FCMP_OGE);
+    bool SamePredClass = (IsLessThan && (PredR == FCmpInst::FCMP_OLT || PredR == FCmpInst::FCMP_OLE)) ||
+                         (IsGreaterThan && (PredR == FCmpInst::FCMP_OGT || PredR == FCmpInst::FCMP_OGE));
+    if (SamePredClass && PredL == PredR && (IsLessThan || IsGreaterThan)) {
+      APFloat::cmpResult CmpResult = LHSC->compare(*RHSC);
+      bool LHSLessThanRHS = (CmpResult == APFloat::cmpLessThan);
+      
+      const FCmpInst *ResultCmp = nullptr;
+      
+      if (IsLessThan) {
+        // For less-than: OR takes larger constant, AND takes smaller
+        if (IsAnd) {
+          // AND: take smaller constant
+          ResultCmp = LHSLessThanRHS ? LHS : RHS;
+        } else {
+          // OR: take larger constant
+          ResultCmp = LHSLessThanRHS ? RHS : LHS;
+        }
+      } else { // IsGreaterThan
+        // For greater-than: OR takes smaller constant, AND takes larger
+        if (IsAnd) {
+          // AND: take larger constant
+          ResultCmp = LHSLessThanRHS ? RHS : LHS;
+        } else {
+          // OR: take smaller constant
+          ResultCmp = LHSLessThanRHS ? LHS : RHS;
+        }
+      }
+      
+      return const_cast<FCmpInst*>(ResultCmp);
+    }
+  }
+
   return nullptr;
 }

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..fe9eaae97033 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1583,6 +1583,77 @@ Value *InstCombinerImpl::foldLogicOfFCmps(FCmpInst *LHS, FCmpInst *RHS,
     }
   }

+  // Simplify OR/AND of comparisons with constants where one implies the other.
+  // For ordered comparisons with the same variable operand:
+  // OR: (x olt C1) | (x olt C2) where C1 < C2 -> (x olt C2)
+  // OR: (x ole C1) | (x ole C2) where C1 < C2 -> (x ole C2)
+  // OR: (x ogt C1) | (x ogt C2) where C1 < C2 -> (x ogt C1)
+  // OR: (x oge C1) | (x oge C2) where C1 < C2 -> (x oge C1)
+  // AND: (x olt C1) & (x olt C2) where C1 < C2 -> (x olt C1)
+  // AND: (x ole C1) & (x ole C2) where C1 < C2 -> (x ole C1)
+  // AND: (x ogt C1) & (x ogt C2) where C1 < C2 -> (x ogt C2)
+  // AND: (x oge C1) & (x oge C2) where C1 < C2 -> (x oge C2)
+  // Simplify OR/AND of comparisons with constants where one implies the other.
+  if (LHS0 == RHS0 &&
+      match(LHS1, m_APFloatAllowPoison(LHSC)) &&
+      match(RHS1, m_APFloatAllowPoison(RHSC))) {
+    LLVM_DEBUG(dbgs() << "Trying to fold OR/AND of FCmps: " << *LHS << " " 
+                      << (IsAnd ? "&" : "|") << " " << *RHS << "\n");
+    bool IsLessThan = (PredL == FCmpInst::FCMP_OLT || PredL == FCmpInst::FCMP_OLE);
+    bool IsGreaterThan = (PredL == FCmpInst::FCMP_OGT || PredL == FCmpInst::FCMP_OGE);
+    bool SamePredClass = (IsLessThan && (PredR == FCmpInst::FCMP_OLT || PredR == FCmpInst::FCMP_OLE)) ||
+                         (IsGreaterThan && (PredR == FCmpInst::FCMP_OGT || PredR == FCmpInst::FCMP_OGE));
+    if (SamePredClass && (IsLessThan || IsGreaterThan)) {
+      APFloat::cmpResult CmpResult = LHSC->compare(*RHSC);
+      bool LHSLessThanRHS = (CmpResult == APFloat::cmpLessThan);
+      
+      FCmpInst::Predicate ResultPred = PredL;
+      const APFloat *ResultConst = LHSC;
+      
+      if (IsLessThan) {
+        // For less-than: OR takes larger constant, AND takes smaller
+        if (IsAnd) {
+          // AND: take smaller constant
+          ResultConst = LHSLessThanRHS ? LHSC : RHSC;
+        } else {
+          // OR: take larger constant
+          ResultConst = LHSLessThanRHS ? RHSC : LHSC;
+        }
+      } else { // IsGreaterThan
+        // For greater-than: OR takes smaller constant, AND takes larger
+        if (IsAnd) {
+          // AND: take larger constant
+          ResultConst = LHSLessThanRHS ? RHSC : LHSC;
+        } else {
+          // OR: take smaller constant
+          ResultConst = LHSLessThanRHS ? LHSC : RHSC;
+        }
+      }
+      
+      // Handle mixed predicates (olt vs ole)
+      if ((PredL == FCmpInst::FCMP_OLT && PredR == FCmpInst::FCMP_OLE) ||
+          (PredL == FCmpInst::FCMP_OLE && PredR == FCmpInst::FCMP_OLT)) {
+        // For mixed less-than predicates, use ole for OR, olt for AND
+        ResultPred = IsAnd ? FCmpInst::FCMP_OLT : FCmpInst::FCMP_OLE;
+        // Need to adjust constant: olt C1 | ole C2 where C1 < C2 -> ole C2
+        // olt C1 | ole C2 where C2 < C1 -> ole C1
+        // For AND: olt C1 & ole C2 where C1 < C2 -> olt C1
+      } else if ((PredL == FCmpInst::FCMP_OGT && PredR == FCmpInst::FCMP_OGE) ||
+                 (PredL == FCmpInst::FCMP_OGE && PredR == FCmpInst::FCMP_OGE)) {
+        // Similar for greater-than
+        ResultPred = IsAnd ? FCmpInst::FCMP_OGT : FCmpInst::FCMP_OGE;
+      }
+      
+      FastMathFlags NewFlag = LHS->getFastMathFlags();
+      if (!IsLogicalSelect)
+        NewFlag |= RHS->getFastMathFlags();
+      
+      return Builder.CreateFCmpFMF(ResultPred, LHS0,
+                                   ConstantFP::get(LHS0->getType(), *ResultConst),
+                                   NewFlag);
+    }
+  }
+
   return nullptr;
 }

